"use client"

import * as React from "react"
import type { JsonSchemaLike } from "lemma-sdk"
import { useSchemaForm } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import { cn } from "@/lib/utils"

export interface LemmaSchemaFormProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onSubmit"> {
  schema?: JsonSchemaLike | null
  uiSchema?: Record<string, unknown> | null
  initialValues?: Record<string, unknown>
  title?: string
  description?: string
  submitLabel?: string
  disabled?: boolean
  onSubmit?: (data: Record<string, unknown>) => Promise<void> | void
  onSubmitted?: (data: Record<string, unknown>) => void
  showReset?: boolean
  resetLabel?: string
  hiddenFields?: string[]
  fieldLabels?: Record<string, string>
  fieldDescriptions?: Record<string, string>
}

export const LemmaSchemaForm = React.forwardRef<HTMLDivElement, LemmaSchemaFormProps>(
  ({
    schema,
    uiSchema,
    initialValues,
    title = "Schema Form",
    description = "Generated from JSON Schema.",
    submitLabel = "Submit",
    disabled = false,
    onSubmit,
    onSubmitted,
    showReset = true,
    resetLabel = "Reset",
    hiddenFields = [],
    fieldLabels,
    fieldDescriptions,
    className,
    ...props
  }, ref) => {
  const form = useSchemaForm({
    schema,
    uiSchema,
    initialValues,
    onSubmit: async (data) => {
      await onSubmit?.(data)
      onSubmitted?.(data)
    },
  })

  const hasFields = form.fields.length > 0

  const handleSubmit = React.useCallback(async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault()
    await form.submit()
  }, [form])

  return (
    <Card ref={ref} className={cn("", className)} {...props}>
      <CardHeader>
        <CardTitle>{title}</CardTitle>
        <CardDescription>{description}</CardDescription>
      </CardHeader>
      <CardContent>
        <form className="grid gap-4" onSubmit={handleSubmit}>
          {form.error ? (
            <div className="rounded-md border border-destructive/40 bg-destructive/10 px-4 py-3 text-sm text-destructive">
              {form.error.message}
            </div>
          ) : null}

          {!hasFields ? (
            <div className="rounded-md border border-dashed border-border bg-muted/30 px-4 py-8 text-sm text-muted-foreground">
              This schema does not define any editable fields.
            </div>
          ) : null}

          {form.fields
            .filter((field) => !hiddenFields.includes(field.name))
            .map((field) => {
            const value = form.values[field.name]
            const error = form.fieldErrors[field.name]
            const resolvedLabel = fieldLabels?.[field.name] ?? field.label
            const resolvedDescription = fieldDescriptions?.[field.name] ?? field.description
            const commonLabel = (
              <div className="grid gap-1.5">
                <Label htmlFor={field.name}>
                  {resolvedLabel}
                  {field.required ? " *" : ""}
                </Label>
                {resolvedDescription ? (
                  <p className="text-sm text-muted-foreground">{resolvedDescription}</p>
                ) : null}
              </div>
            )

            if (field.kind === "boolean") {
              return (
                <div key={field.name} className="grid gap-2 rounded-lg border border-border bg-muted/30 p-4">
                  {commonLabel}
                  <label className="flex items-center gap-3 text-sm">
                    <Checkbox
                      checked={Boolean(value)}
                      onCheckedChange={(checked) => form.setValue(field.name, checked === true)}
                    />
                    <span>{Boolean(value) ? "Enabled" : "Disabled"}</span>
                  </label>
                  {error ? <p className="text-sm text-destructive">{error}</p> : null}
                </div>
              )
            }

            if (field.kind === "select") {
              return (
                <div key={field.name} className="grid gap-2">
                  {commonLabel}
                  <Select
                    value={typeof value === "string" ? value : ""}
                    onValueChange={(nextValue) => form.setValue(field.name, nextValue)}
                  >
                    <SelectTrigger id={field.name}>
                      <SelectValue placeholder={`Select ${field.label.toLowerCase()}`} />
                    </SelectTrigger>
                    <SelectContent>
                      {field.options.map((option) => (
                        <SelectItem key={option.value} value={option.value}>
                          {option.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {error ? <p className="text-sm text-destructive">{error}</p> : null}
                </div>
              )
            }

            if (field.kind === "json" || field.kind === "textarea") {
              return (
                <div key={field.name} className="grid gap-2">
                  {commonLabel}
                  <Textarea
                    id={field.name}
                    rows={field.kind === "json" ? 8 : 4}
                    value={typeof value === "string" ? value : ""}
                    onChange={(event) => form.setValue(field.name, event.target.value)}
                  />
                  {error ? <p className="text-sm text-destructive">{error}</p> : null}
                </div>
              )
            }

            return (
              <div key={field.name} className="grid gap-2">
                {commonLabel}
                <Input
                  id={field.name}
                  type={
                    field.kind === "number"
                      ? "number"
                      : field.kind === "date"
                        ? "date"
                        : field.kind === "datetime"
                          ? "datetime-local"
                          : field.kind === "email"
                            ? "email"
                            : "text"
                  }
                  value={typeof value === "string" ? value : value ? String(value) : ""}
                  onChange={(event) => form.setValue(field.name, event.target.value)}
                />
                {error ? <p className="text-sm text-destructive">{error}</p> : null}
              </div>
            )
          })}

          <div className="flex items-center gap-2 pt-2">
            <Button disabled={disabled || form.isSubmitting} type="submit">
              {form.isSubmitting ? "Submitting…" : submitLabel}
            </Button>
            {showReset ? (
              <Button
                disabled={disabled || form.isSubmitting}
                onClick={() => form.reset()}
                type="button"
                variant="outline"
              >
                {resetLabel}
              </Button>
            ) : null}
          </div>
        </form>
      </CardContent>
    </Card>
  )
})
LemmaSchemaForm.displayName = "LemmaSchemaForm"

"use client"

import * as React from "react"
import type { FlowRun, LemmaClient } from "lemma-sdk"
import { useWorkflowStart } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { LemmaSchemaForm } from "@/components/lemma/lemma-schema-form"
import { cn } from "@/lib/utils"

export interface LemmaWorkflowStartFormProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onError" | "onSubmit"> {
  client: LemmaClient
  podId?: string
  workflowName: string
  title?: string
  description?: string
  submitLabel?: string
  initialValues?: Record<string, unknown>
  onStarted?: (run: FlowRun) => void
  onError?: (error: Error) => void
}

export const LemmaWorkflowStartForm = React.forwardRef<HTMLDivElement, LemmaWorkflowStartFormProps>(
  ({
    client,
    podId,
    workflowName,
    title = "Start Workflow",
    description = "Launch a workflow with a schema-aware form when input is required.",
    submitLabel = "Start workflow",
    initialValues,
    onStarted,
    onError,
    className,
    ...props
  }, ref) => {
  const hasWorkflowName = workflowName.trim().length > 0

  const workflow = useWorkflowStart({
    client,
    podId,
    workflowName,
  })

  React.useEffect(() => {
    if (workflow.error) {
      onError?.(workflow.error)
    }
  }, [workflow.error, onError])

  const handleStart = React.useCallback(async (data: Record<string, unknown>) => {
    try {
      const run = await workflow.start(data)
      onStarted?.(run)
    } catch (err) {
      onError?.(err instanceof Error ? err : new Error(String(err)))
    }
  }, [onStarted, onError, workflow])

  if (!hasWorkflowName) {
    return (
      <Card ref={ref} className={cn("", className)} {...props}>
        <CardHeader>
          <CardTitle>{title}</CardTitle>
          <CardDescription>{description}</CardDescription>
        </CardHeader>
      </Card>
    )
  }

  if (!workflow.workflow && workflow.isLoadingWorkflow) {
    return (
      <Card ref={ref} className={cn("", className)} {...props}>
        <CardHeader>
          <CardTitle>{title}</CardTitle>
          <CardDescription>Loading workflow definition…</CardDescription>
        </CardHeader>
      </Card>
    )
  }

  if (!workflow.inputSchema || Object.keys(workflow.inputSchema).length === 0) {
    return (
      <Card ref={ref} className={cn("", className)} {...props}>
        <CardHeader>
          <CardTitle>{title}</CardTitle>
          <CardDescription>{description}</CardDescription>
        </CardHeader>
        <CardContent className="grid gap-4">
          {workflow.error ? (
            <div className="rounded-md border border-destructive/40 bg-destructive/10 px-4 py-3 text-sm text-destructive">
              {workflow.error.message}
            </div>
          ) : null}
          <Button
            disabled={workflow.isStarting}
            onClick={() => {
              void workflow.start(initialValues ?? {}).then((run) => {
                onStarted?.(run)
              })
            }}
            type="button"
          >
            {workflow.isStarting ? "Starting…" : submitLabel}
          </Button>
        </CardContent>
      </Card>
    )
  }

  return (
    <LemmaSchemaForm
      ref={ref}
      className={className}
      description={description}
      disabled={workflow.isStarting}
      initialValues={initialValues}
      onSubmit={handleStart}
      schema={workflow.inputSchema}
      submitLabel={workflow.isStarting ? "Starting…" : submitLabel}
      title={title}
      uiSchema={workflow.inputUiSchema}
      {...props}
    />
  )
})
LemmaWorkflowStartForm.displayName = "LemmaWorkflowStartForm"

"use client"

import * as React from "react"
import type { FlowRun } from "lemma-sdk"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { cn } from "@/lib/utils"

export interface LemmaWorkflowRunDetailsProps extends React.HTMLAttributes<HTMLDivElement> {
  run?: FlowRun | null
  isLoading?: boolean
  error?: Error | null
  title?: string
  description?: string
}

function formatJson(value: unknown): string {
  if (value === null || typeof value === "undefined") return ""
  try {
    return JSON.stringify(value, null, 2)
  } catch {
    return String(value)
  }
}

export const LemmaWorkflowRunDetails = React.forwardRef<HTMLDivElement, LemmaWorkflowRunDetailsProps>(
  ({
    run,
    isLoading,
    error,
    title = "Workflow Run Details",
    description = "Inspect execution context, stack, and step history.",
    className,
    ...props
  }, ref) => {
  return (
    <Card ref={ref} className={cn("", className)} {...props}>
      <CardHeader>
        <CardTitle>{title}</CardTitle>
        <CardDescription>{description}</CardDescription>
      </CardHeader>
      <CardContent className="grid gap-4">
        {error ? (
          <div className="rounded-md border border-destructive/40 bg-destructive/10 px-4 py-3 text-sm text-destructive">
            {error.message}
          </div>
        ) : null}
        {isLoading ? (
          <div className="rounded-md border border-dashed border-border bg-muted/30 px-4 py-8 text-sm text-muted-foreground animate-pulse">
            Loading run details…
          </div>
        ) : !run ? (
          <div className="rounded-md border border-dashed border-border bg-muted/30 px-4 py-8 text-sm text-muted-foreground">
            Select a workflow run to inspect details.
          </div>
        ) : (
          <>
            <pre className="max-h-[320px] overflow-auto rounded-md border border-border bg-muted/40 p-4 text-sm leading-6">
              {formatJson(run.execution_context ?? {})}
            </pre>
            <pre className="max-h-[320px] overflow-auto rounded-md border border-border bg-muted/40 p-4 text-sm leading-6">
              {formatJson({
                execution_stack: run.execution_stack ?? [],
                step_history: run.step_history ?? [],
              })}
            </pre>
          </>
        )}
      </CardContent>
    </Card>
  )
})
LemmaWorkflowRunDetails.displayName = "LemmaWorkflowRunDetails"

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useWorkflowRuns } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { cn } from "@/lib/utils"

export interface LemmaWorkflowHistoryProps extends React.HTMLAttributes<HTMLDivElement> {
  client: LemmaClient
  podId?: string
  workflowName: string
  title?: string
  description?: string
  onRunSelect?: (runId: string | null) => void
}

export const LemmaWorkflowHistory = React.forwardRef<HTMLDivElement, LemmaWorkflowHistoryProps>(
  ({
    client,
    podId,
    workflowName,
    title = "Workflow History",
    description = "Recent runs for the selected workflow.",
    onRunSelect,
    className,
    ...props
  }, ref) => {
  const history = useWorkflowRuns({
    client,
    podId,
    workflowName,
    enabled: workflowName.trim().length > 0,
  })

  return (
    <Card ref={ref} className={cn("", className)} {...props}>
      <CardHeader>
        <div className="flex items-start justify-between gap-3">
          <div className="grid gap-1">
            <CardTitle>{title}</CardTitle>
            <CardDescription>{description}</CardDescription>
          </div>
          <Button
            disabled={history.isLoading || !workflowName}
            onClick={() => {
              void history.refresh()
            }}
            variant="outline"
          >
            {history.isLoading ? "Refreshing..." : "Refresh"}
          </Button>
        </div>
      </CardHeader>
      <CardContent className="flex flex-col gap-4">
        {history.error ? (
          <div className="rounded-md border border-destructive/40 bg-destructive/10 px-4 py-3 text-sm text-destructive">
            {history.error.message}
          </div>
        ) : null}
        {history.runs.length === 0 ? (
          <div className="rounded-md border border-dashed border-border bg-muted/30 px-4 py-8 text-sm text-muted-foreground">
            No workflow runs loaded.
          </div>
        ) : (
          history.runs.map((run) => {
            const runId = run.id ?? null
            const selected = runId === history.effectiveSelectedRunId
            return (
              <button
                className="rounded-md border border-border bg-muted/30 p-4 text-left text-sm transition-colors hover:bg-muted data-[selected=true]:border-primary"
                data-selected={selected}
                key={run.id ?? `${run.flow_id}-${run.created_at}`}
                onClick={() => {
                  history.selectRun(runId)
                  onRunSelect?.(runId)
                }}
                type="button"
              >
                <div className="flex items-center justify-between gap-3">
                  <span className="font-medium">{run.status ?? "UNKNOWN"}</span>
                  <span className="text-sm text-muted-foreground">{run.created_at ?? "no timestamp"}</span>
                </div>
                <div className="mt-1 truncate text-sm text-muted-foreground">{run.id ?? "missing run id"}</div>
              </button>
            )
          })
        )}
        {history.nextPageToken ? (
          <Button
            disabled={history.isLoadingMore}
            onClick={() => {
              void history.loadMore()
            }}
            variant="outline"
          >
            {history.isLoadingMore ? "Loading..." : "Load more"}
          </Button>
        ) : null}
      </CardContent>
    </Card>
  )
})
LemmaWorkflowHistory.displayName = "LemmaWorkflowHistory"

"use client"

import * as React from "react"
import type { FlowRun, LemmaClient, Workflow } from "lemma-sdk"
import {
  Card,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { LemmaWorkflowHistory } from "@/components/lemma/lemma-workflow-history"
import { LemmaWorkflowRunDetails } from "@/components/lemma/lemma-workflow-run-details"
import { LemmaWorkflowRunStatus } from "@/components/lemma/lemma-workflow-run-status"
import { LemmaWorkflowStartForm } from "@/components/lemma/lemma-workflow-start-form"
import { cn } from "@/lib/utils"

export interface LemmaWorkflowLauncherPageProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onError"> {
  client: LemmaClient
  podId?: string
  workflows?: Workflow[]
  workflowName?: string
  onWorkflowNameChange?: (workflowName: string) => void
  title?: string
  description?: string
  onError?: (error: Error) => void
}

export const LemmaWorkflowLauncherPage = React.forwardRef<HTMLDivElement, LemmaWorkflowLauncherPageProps>(
  ({
    client,
    podId,
    workflows = [],
    workflowName,
    onWorkflowNameChange,
    title = "Workflow Launcher",
    description = "Start a workflow and review its recent run history.",
    onError,
    className,
    ...props
  }, ref) => {
  const [internalWorkflowName, setInternalWorkflowName] = React.useState(workflowName ?? workflows[0]?.name ?? "")
  const [lastRun, setLastRun] = React.useState<FlowRun | null>(null)
  const selectedWorkflowName = workflowName ?? internalWorkflowName

  React.useEffect(() => {
    if (workflowName) return
    setInternalWorkflowName((current) => (
      current && workflows.some((workflow) => workflow.name === current) ? current : (workflows[0]?.name ?? "")
    ))
  }, [workflowName, workflows])

  const setSelectedWorkflowName = React.useCallback((nextWorkflowName: string) => {
    if (!workflowName) setInternalWorkflowName(nextWorkflowName)
    onWorkflowNameChange?.(nextWorkflowName)
  }, [onWorkflowNameChange, workflowName])

  return (
    <div ref={ref} className={cn("grid gap-4", className)} {...props}>
      <Card>
        <CardHeader>
          <CardTitle>{title}</CardTitle>
          <CardDescription>{description}</CardDescription>
        </CardHeader>
        <div className="px-6 pb-6">
          <Select value={selectedWorkflowName} onValueChange={setSelectedWorkflowName}>
            <SelectTrigger>
              <SelectValue placeholder="Select a workflow" />
            </SelectTrigger>
            <SelectContent>
              {workflows.map((workflow) => (
                <SelectItem key={workflow.name} value={workflow.name}>
                  {workflow.name}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </Card>

      {selectedWorkflowName ? (
        <div className="grid gap-4 xl:grid-cols-[minmax(0,1fr)_minmax(320px,0.8fr)]">
    <div>
            <LemmaWorkflowStartForm
              client={client}
              onError={onError}
              onStarted={(run) => setLastRun(run)}
              podId={podId}
              workflowName={selectedWorkflowName}
            />
            <LemmaWorkflowRunStatus run={lastRun} />
            <LemmaWorkflowRunDetails run={lastRun} />
          </div>
          <LemmaWorkflowHistory
            client={client}
            podId={podId}
            workflowName={selectedWorkflowName}
          />
        </div>
      ) : (
        <Card>
          <CardHeader>
            <CardTitle>No Workflow Selected</CardTitle>
            <CardDescription>Pass workflows or a workflowName to render the launcher.</CardDescription>
          </CardHeader>
        </Card>
      )}
    </div>
  )
})
LemmaWorkflowLauncherPage.displayName = "LemmaWorkflowLauncherPage"
